  "verses": [
    {
      "n": 14,
      "column": "left",
      "text": "Divisimts Kasas/ un di-\ntwidesmits Ahschus / divisimts\nAwis/ un diwidesmits Aunus.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Trihsdesimits sihdoschas\nRameeku-Mahtes/ar fatweem Ku-\nmeteem/tfchetrdefimits Gohwis/\nun defimits Wehrschus / diwide-\nmits Ehsela-Mahtes/un defimits\nRumekus.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un dewe tohs fawo Kalpu\nRohkâ/ ikkatru Pulku fewischki/\nun fazzija us fatweem Kalpeem:\nEita juhs man papreefschu / un\npametteet Starpibu starp ikwee-\nnu Pulku.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un wiꞥſch patwehſeja tam pahrwedde tohs pahr to\npirmajam/ fazzidans: Kad Ee-\nfaws mans Brahls tewfastaps/\nun tew waizahs / un fazzihis:\npats.\nKam tu peederri/ un us kurren tu\neij/ un kam peederr fchee/kas tawâ\nPreekscha?\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Tad buhs tew fazziht: Tee\npeederr tawam Kalpam Jehka-\nbam/ tas fuhta fawam Kungam\nCesawain Dahwanu/ un redsi /\nwiꞥſch pats irr arridsan pakkat\nmums.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Un wiꞥſch patwehſeja ar-\nridsan tam ohtraim/ un tam tre-\nſchain/ un wiſſeem/ kas tohs Loh-\npus dsinne / fazzidans: Pehz\nſchein Wahrdeem buhs jums\nfazziht us Cesawu/kad juhs to at-\nrasfeet.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Un jums buhs arridsan\nfazziht: Rangi / taivs Kalps jo tu effi zihntjees ar Deew\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Jehkabs irr pakkat mum\nwiꞥſch fazzija : Es fam\nfchu winna Watgu ar fcho\nwanit/ kas man papreeffch\nun pehz to redſefchu es\nWaigu/ kas finna/ wiꞥſch\nnis peenems.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Tad aisgahje nu ta-\nwana/ winnam papreeffch\nwiꞥſch pats palikfe to Na-\nsatva Pulka.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un wiꞥſch zehluhs\nNakti / un nehme faivas\nSeewas/ un fawas diwi\nnes / un fawus weenpad\nBehrnus / un gahje pee\nPahrzelfamas-Weetas Ja\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un wiꞥſch nehme ta-\nun wiꞥſch pahrwedde / ka-\nbij / bet Jehkabs palikfe\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Tad zihnijahs weens\nar to/ famehr Deena fahze\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un kad tas redſeja/\nwinau ne pahrspehja / ate\ntas winna Ziskas Lohzelfli/\ntas Lohzelflis pee Jehkaba\nzihkstoht isgreesahs.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Un tas fazzija : P\nmann/ jo Gaifina jaw rah\nbet wiꞥſch atbildeja/ es t\npalatifschu/jatu mann ne fi\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Un tas fazzija us w\nKas irr taws Wahrdss? un\nfazzija/ Jehkabs.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Tad fazzija tas: Ta-\nWahrdam ne buhs wairs\nlabs fauktam tapt / bet Jfi\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
